import React, { useState, useEffect, useContext } from 'react';
import {
	Container,
	Box,
	Typography,
	Card,
	CardContent,
	CircularProgress,
	Alert,
	Grid,
	Paper,
} from '@mui/material';
import { AuthContext } from '../context/AuthContext';
import api from '../api';
import KanbanBoard from '../components/KanbanBoard';

export default function EmployeeDashboard() {
	const { user } = useContext(AuthContext);
	const [tasks, setTasks] = useState([]);
	const [progressions, setProgressions] = useState([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState('');

	const fetchData = async () => {
		setLoading(true);
		try {
			const [proRes, taskRes] = await Promise.all([
				api.get('/task-progressions'),
				api.get(`/my-tasks/${user?.id}`),
			]);

			const progBody = proRes.data;
			const progList = Array.isArray(progBody) ? progBody : (progBody.progressions ?? progBody.data ?? []);
			setProgressions(progList || []);

			const taskBody = taskRes.data;
			const taskList = Array.isArray(taskBody) ? taskBody : (taskBody.tasks ?? taskBody.data ?? []);
			setTasks(taskList || []);

			setError('');
		} catch (err) {
			console.error('Failed to load data', err);
			setError('Failed to load tasks');
		} finally {
			setLoading(false);
		}
	};

	useEffect(() => {
		if (user?.id) {
			fetchData();
		}
	}, [user?.id]);

	const getTaskStats = () => {
		return {
			pending: tasks.filter((t) => !t.progression_step && t.status === 'pending').length,
			in_progress: tasks.filter((t) => !t.progression_step && t.status === 'in_progress').length,
			completed: tasks.filter((t) => !t.progression_step && t.status === 'completed').length,
		};
	};

	const getColumns = () => {
		if (selectedProgressionId === 'default') {
			return [
				{ id: null, name: 'To Do', key: 'pending' },
				{ id: null, name: 'In Progress', key: 'in_progress' },
				{ id: null, name: 'Done', key: 'completed' },
			];
		}

		const prog = progressions.find((p) => String(p.id) === String(selectedProgressionId));
		return prog?.steps?.sort((a, b) => a.sort_order - b.sort_order) || [];
	};

	const getTasksByColumn = () => {
		const cols = getColumns();

		if (selectedProgressionId === 'default') {
			return {
				'pending': tasks.filter((t) => !t.progression_step && t.status === 'pending'),
				'in_progress': tasks.filter((t) => !t.progression_step && t.status === 'in_progress'),
				'completed': tasks.filter((t) => !t.progression_step && t.status === 'completed'),
			};
		}

		const map = {};
		cols.forEach((c) => (map[c.id] = []));
		tasks
			.filter((t) => String(t.progression?.id) === String(selectedProgressionId))
			.forEach((task) => {
				const key = task.progression_step?.id ?? null;
				if (map[key]) map[key].push(task);
				else if (cols.length > 0) map[cols[0].id].push(task);
			});
		return map;
	};

	const handleMoveTask = async (taskId, info) => {
		try {
			const column = info.column;
			if (selectedProgressionId === 'default') {
				await api.patch(`/tasks/${taskId}/status`, { status: column });
			} else {
				await api.patch(`/tasks/${taskId}/status`, { task_progression_step_id: column });
			}
			await fetchData();
		} catch (err) {
			console.error('Failed to move task', err);
		}
	};

	const stats = getTaskStats();

	return (
		<Box sx={{ backgroundColor: '#F8FAFC', minHeight: 'calc(100vh - 64px)', py: 4 }}>
			<Container maxWidth="xl">
				<Box sx={{ mb: 6 }}>
					<Typography variant="h3" sx={{ fontWeight: 800, mb: 1, color: '#0F172A' }}>
						My Tasks
					</Typography>
					<Typography variant="body1" sx={{ color: '#64748B' }}>
						Track and manage your assigned work
					</Typography>
				</Box>

				<Grid container spacing={3} sx={{ mb: 4 }}>
					{[
						{ label: 'To Do', value: stats.pending, color: '#FEF3C7', textColor: '#92400E' },
						{ label: 'In Progress', value: stats.in_progress, color: '#E0F2FE', textColor: '#0369A1' },
						{ label: 'Done', value: stats.completed, color: '#DCFCE7', textColor: '#065F46' },
					].map((stat) => (
						<Grid item xs={12} sm={6} md={3} key={stat.label}>
							<Card sx={{ 
								border: '1px solid #E2E8F0', 
								borderLeft: `4px solid ${stat.textColor}`,
								backgroundColor: stat.color,
								transition: 'transform 0.2s',
								'&:hover': { transform: 'translateY(-2px)' }
							}}>
								<CardContent sx={{ textAlign: 'center' }}>
									<Typography variant="h3" sx={{ color: stat.textColor, fontWeight: 700, mb: 1 }}>
										{stat.value}
									</Typography>
									<Typography variant="body2" sx={{ color: stat.textColor }}>
										{stat.label}
									</Typography>
								</CardContent>
							</Card>
						</Grid>
					))}
				</Grid>

				{error && (
					<Alert severity="error" sx={{ mb: 4, borderRadius: 2 }}>
						{error}
					</Alert>
				)}

				{/* Progression Tabs */}
				{!loading && tasks.length > 0 && (
					<Paper
						elevation={0}
						sx={{
							mb: 4,
							p: 2,
							backgroundColor: '#fff',
							border: '1px solid #E2E8F0',
							borderRadius: 2,
							display: 'flex',
							gap: 1,
							alignItems: 'center',
							flexWrap: 'wrap',
						}}
					>
						<Chip
							label="Default"
							onClick={() => setSelectedProgressionId('default')}
							variant={selectedProgressionId === 'default' ? 'filled' : 'outlined'}
							sx={{
								bgcolor: selectedProgressionId === 'default' ? '#06B6D4' : 'transparent',
								color: selectedProgressionId === 'default' ? '#fff' : '#64748B',
								borderColor: '#E2E8F0',
								fontWeight: 600,
							}}
						/>
						{progressions.map((prog) => (
							<Chip
								key={prog.id}
								label={prog.name}
								onClick={() => setSelectedProgressionId(String(prog.id))}
								variant={String(selectedProgressionId) === String(prog.id) ? 'filled' : 'outlined'}
								sx={{
									bgcolor: String(selectedProgressionId) === String(prog.id) ? '#06B6D4' : 'transparent',
									color: String(selectedProgressionId) === String(prog.id) ? '#fff' : '#64748B',
									borderColor: '#E2E8F0',
									fontWeight: 600,
								}}
							/>
						))}
					</Paper>
				)}

				{loading ? (
					<Box sx={{ display: 'flex', justifyContent: 'center', py: 6 }}>
						<CircularProgress />
					</Box>
				) : tasks.length === 0 ? (
					<Card sx={{ backgroundColor: '#fff', border: '1px solid #E2E8F0', textAlign: 'center', py: 6 }}>
						<Typography variant="h6" sx={{ color: '#0F172A', mb: 1 }}>
							No tasks assigned yet
						</Typography>
						<Typography variant="body2" sx={{ color: '#64748B' }}>
							Check back soon for new assignments from your team lead.
						</Typography>
					</Card>
				) : (
					<Box>
						<KanbanBoard
							columns={getColumns()}
							tasksByColumn={getTasksByColumn()}
							currentUser={user}
							canDragTask={(task, currentUser) => task.assigned_users?.some((u) => u.id === currentUser?.id)}
							onMoveTask={handleMoveTask}
						/>
					</Box>
				)}
			</Container>
		</Box>
	);
}
